function normalize(values) {
    if (!values || !Array.isArray(values)) return [];
    return values.map(v => ({
        time: new Date(v.datetime),
        open: parseFloat(v.open),
        high: parseFloat(v.high),
        low: parseFloat(v.low),
        close: parseFloat(v.close),
    }));
}

function sortFn(a, b) {
    return a.time - b.time;
}

const items = $input.all();
const results = [];

for (const item of items) {
    if (item.json.data && Array.isArray(item.json.data)) {
        for (const dataItem of item.json.data) {
            if (dataItem && dataItem.meta) {
                results.push({
                    json: {
                        ticker: dataItem.meta.symbol,
                        timeframe: dataItem.meta.interval,
                        candles: normalize(dataItem.values).sort(sortFn)
                    }
                });
            }
            else if (dataItem && dataItem.data && Array.isArray(dataItem.data)) {
                for (const nested of dataItem.data) {
                    if (nested && nested.meta) {
                        results.push({
                            json: {
                                ticker: nested.meta.symbol,
                                timeframe: nested.meta.interval,
                                candles: normalize(nested.values).sort(sortFn)
                            }
                        });
                    }
                }
            }
        }
    }
    else if (item.json.meta) {
        results.push({
            json: {
                ticker: item.json.meta.symbol,
                timeframe: item.json.meta.interval,
                candles: normalize(item.json.values).sort(sortFn)
            }
        });
    }
}

if (results.length === 0) {
    return [{ json: { error: 'Could not process candle data', debug: JSON.stringify(items[0]?.json).substring(0, 500) } }];
}

return results;

const inputData = $input.all();
let result = {};

function safeGet(obj, path, defaultValue = null) {
    try {
        return path.split('.').reduce((o, p) => o && o[p], obj) ?? defaultValue;
    } catch {
        return defaultValue;
    }
}

inputData.forEach(item => {
    const data = item.json;
    if (data.dividends) {
        result.dividends = {
            data: data.dividends,
            count: data.dividends?.length || 0,
            latest: data.dividends?.[0] || null,
            annualDividend: calculateAnnualDividend(data.dividends)
        };
    }
    if (data.earnings) {
        result.earnings = {
            data: data.earnings,
            latest: data.earnings?.[0] || null,
            epsGrowth: calculateEPSGrowth(data.earnings)
        };
    }
    if (data.statistics) {
        result.statistics = {
            peRatio: safeGet(data, 'statistics.valuations_metrics.pe_ratio'),
            pegRatio: safeGet(data, 'statistics.valuations_metrics.peg_ratio'),
            priceToBook: safeGet(data, 'statistics.valuations_metrics.pb_ratio'),
            roe: safeGet(data, 'statistics.financials_metrics.return_on_equity'),
            roa: safeGet(data, 'statistics.financials_metrics.return_on_assets'),
            debtToEquity: safeGet(data, 'statistics.financials_metrics.debt_equity_ratio'),
            currentRatio: safeGet(data, 'statistics.financials_metrics.current_ratio'),
            dividendYield: safeGet(data, 'statistics.financials_metrics.dividend_yield')
        };
    }
    if (data.symbol || data.name) {
        result.profile = {
            symbol: data.symbol,
            name: data.name,
            country: data.country,
            sector: data.sector,
            industry: data.industry,
            website: data.website,
            description: data.description
        };
    }
});

function calculateAnnualDividend(dividends) {
    if (!dividends || dividends.length === 0) return 0;
    const oneYearAgo = new Date();
    oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);
    return dividends
        .filter(d => new Date(d.ex_date) >= oneYearAgo)
        .reduce((sum, d) => sum + parseFloat(d.amount || 0), 0);
}

function calculateEPSGrowth(earnings) {
    if (!earnings || earnings.length < 2) return null;
    const latest = parseFloat(earnings[0]?.eps_estimate || earnings[0]?.eps_actual || 0);
    const previous = parseFloat(earnings[1]?.eps_estimate || earnings[1]?.eps_actual || 0);
    if (previous === 0) return null;
    return ((latest - previous) / previous) * 100;
}

function calculateLongTermMetrics() {
    const metrics = {};
    if (result.statistics?.dividendYield) {
        metrics.dividendYield = parseFloat(result.statistics.dividendYield);
    }
    let expectedReturn = 0;
    let returnComponents = [];
    if (metrics.dividendYield) {
        expectedReturn += metrics.dividendYield;
        returnComponents.push(`Dividend Yield: ${metrics.dividendYield.toFixed(2)}%`);
    }
    if (result.earnings?.epsGrowth && result.earnings.epsGrowth > 0) {
        const growthContribution = Math.min(result.earnings.epsGrowth, 15);
        expectedReturn += growthContribution;
        returnComponents.push(`Earnings Growth: ${growthContribution.toFixed(2)}%`);
    }
    if (result.statistics?.peRatio) {
        const pe = parseFloat(result.statistics.peRatio);
        if (pe > 0) {
            let valuationAdjustment = 0;
            if (pe < 15) valuationAdjustment = 2;
            else if (pe > 25) valuationAdjustment = -3;
            expectedReturn += valuationAdjustment;
            if (valuationAdjustment !== 0) {
                returnComponents.push(`Valuation Adjustment: ${valuationAdjustment.toFixed(2)}%`);
            }
        }
    }
    metrics.expectedAnnualReturn = Math.max(0, expectedReturn);
    metrics.returnComponents = returnComponents;
    return metrics;
}

result.longTermMetrics = calculateLongTermMetrics();

return [{
    json: {
        fundamentalAnalysis: result,
        stockSymbol: result.profile?.symbol || 'Unknown',
        stockName: result.profile?.name || 'Unknown Company'
    }
}];

