const newsData = $input.all();

async function fetchArticleContent(url) {
    try {
        const response = await fetch(url);
        if (!response.ok) return null;
        const html = await response.text();
        const parser = new DOMParser();
        const doc = parser.parseFromString(html, 'text/html');
        const selectors = ['.article-body', '.post-content', '.story-body', 'article', 'main'];
        let articleText = '';
        for (const selector of selectors) {
            const elements = doc.querySelectorAll(selector);
            if (elements.length > 0) {
                elements.forEach(el => articleText += ' ' + el.textContent);
                break;
            }
        }
        if (articleText.length < 100) {
            doc.querySelectorAll('p').forEach(p => {
                const text = p.textContent.trim();
                if (text.length > 50) articleText += ' ' + text;
            });
        }
        return articleText.replace(/\s+/g, ' ').trim();
    } catch (error) {
        return null;
    }
}

async function processArticles() {
    const results = [];
    for (const item of newsData) {
        const articles = item.json.rss.channel.item;
        if (articles && Array.isArray(articles)) {
            for (const article of articles) {
                results.push({
                    json: {
                        title: article.title,
                        description: article.description.replace(/<[^>]*>/g, '').trim(),
                        source: article.source?._ || '',
                        pubDate: article.pubDate,
                        link: article.link
                    }
                });
            }
        }
    }
    return results;
}

return processArticles().catch(error => {
    return [{ json: { error: 'Could not fetch news contents' } }];
});
